sSubset = 'IMF.PAW.SS.ManagedDimensions.Active';
If(SubsetExists(sDimDimension, sSubset) = 1);
  SubsetDestroy(sDimDimension, sSubset);
EndIf;
SubsetCreate(sDimDimension, sSubset);
nIndex = 1;
nCount = DIMSIZ(sDimDimension);
While(nIndex <= nCount);
  sElement = DIMNM(sDimDimension, nIndex);
  If((ElementType(sDimDimension, sDimDimension, sElement) @<> 'Consolidated') & (sElement @<> '__Template.ManagedDimension'));
    SubsetElementInsert(sDimDimension, sSubset, sElement, 1);
  EndIf;
  nIndex = nIndex + 1;
End;

